SELECT 
FROM pdm_tool_template_job_log
WHERE job_id = #{jobId}
AND (is_deleted = 0 OR is_deleted IS NULL)
ORDER BY execute_at DESC
LIMIT #{limit}

SELECT t.id, t.execute_at, t.job_id, t.template_id, t.xxl_job_log_id, t.execute_result, t.success, t.duration_ms, t.error_msg, t.create_time, t.is_deleted FROM pdm_tool_template_job_log t INNER JOIN ( SELECT job_id, MAX(id) AS max_id FROM pdm_tool_template_job_log WHERE (is_deleted = 0 OR is_deleted IS NULL) AND job_id IN
#{id}
GROUP BY job_id ) tmp ON t.id = tmp.max_id
